import { useRef, useState } from "react";
import { createPaymentIntent } from "@/server/payments.server";
import { Field, FieldLabel } from "@/components/ui/field";
import type { CreatePaymentIntentInput } from "@subfico/pay-js-sdk/react";
import {
  confirmPaymentIntent,
  SubFiCreditCardPaymentMethodForm,
  validateForm,
} from "@subfico/pay-js-sdk/react";
import { useForm } from "@tanstack/react-form";
import { createFileRoute } from "@tanstack/react-router";
import { createServerFn } from "@tanstack/react-start";
import { Button, Input } from "@workspace/ui";
import { z } from "zod";

const VITE_SUB_RENDER_TOKEN =
  "eyJhbGciOiJIUzI1NiJ9..kqrVIXCDJLtYrAJJlXsxxeENXSHrA5Z2ObeKgKsnNho";

const createPaymentIntentClient = createServerFn({ method: "POST" })
  .inputValidator(
    z.object({
      email: z.email(),
    }),
  )
  .handler(async ({ data }): Promise<string | undefined> => {
    const email = data.email;
    const paymentIntentCreateAttributes: CreatePaymentIntentInput = {
      // if it don't make dollars then it don't make cents
      amount: 5000,
      capture_method: "automatic",
    };
    const embedToken = await createPaymentIntent({
      customer: { email, name: "Annie Dot" },
      paymentIntent: paymentIntentCreateAttributes,
    });
    return embedToken;
  });

export const Route = createFileRoute(
  "/_authed/campaigns/$campaignId/pages/demo",
)({
  loader: () => {
    return {
      subRenderToken: VITE_SUB_RENDER_TOKEN,
    };
  },
  component: DemoPage,
});

function DemoPage() {
  const { subRenderToken } = Route.useLoaderData();
  const subIframeRef = useRef<HTMLIFrameElement>(null);
  const [formError, setFormError] = useState<string | null>(null);

  const form = useForm({
    defaultValues: {
      email: "",
    },
    onSubmit: async ({ value }) => {
      setFormError(null);
      try {
        const isValid = await validateForm({ iframeRef: subIframeRef });

        if (!isValid) {
          setFormError("Please complete the card form before continuing.");
          return;
        }

        const embedToken = await createPaymentIntentClient({
          data: { email: value.email.trim() },
        });

        confirmPaymentIntent({ iframeRef: subIframeRef, token: embedToken });
      } catch (error) {
        setFormError(error instanceof Error ? error.message : "Unknown error");
      }
    },
  });

  return (
    <form
      className="space-y-4"
      onSubmit={(e) => {
        e.preventDefault();
        e.stopPropagation();
        form.handleSubmit();
      }}
    >
      <form.Field
        name="email"
        validators={{
          onSubmit: ({ value }) => {
            const trimmed = value.trim();
            if (!trimmed) {
              return "Email is required";
            }
            const parsed = z.email().safeParse(trimmed);
            return parsed.success ? undefined : "Enter a valid email";
          },
        }}
        children={(field) => (
          <Field>
            <FieldLabel htmlFor="demo-pay-email">Email</FieldLabel>
            <Input
              autoComplete="email"
              className="h-10"
              id="demo-pay-email"
              name={field.name}
              onBlur={field.handleBlur}
              onChange={(e) => field.handleChange(e.target.value)}
              type="email"
              value={field.state.value}
            />
          </Field>
        )}
      />

      <SubFiCreditCardPaymentMethodForm
        ref={subIframeRef}
        renderToken={subRenderToken}
        additionalFields={{ cardholderName: true }}
        onPaymentIntentConfirmationSucceeded={(paymentIntent) => {
          console.log("Payment succeeded:", paymentIntent.id);
        }}
        onSetupIntentConfirmationSucceeded={() => {}}
        onConfirmationFailed={(errorMessage) => {
          setFormError(errorMessage);
        }}
      />

      {formError ? (
        <p className="text-destructive text-sm" role="alert">
          {formError}
        </p>
      ) : null}

      <form.Subscribe
        selector={(state) => [state.canSubmit, state.isSubmitting]}
        children={([canSubmit, isSubmitting]) => (
          <Button type="submit" disabled={!canSubmit || isSubmitting}>
            {isSubmitting ? "Processing..." : "Pay Now"}
          </Button>
        )}
      />
    </form>
  );
}
